  5	  DropdownGroup,
  6	  DropdownItem,
  7	  MenuToggle,
  8	  MenuToggleElement,
  9	  Radio,
 10	  Text,
 11	  TextVariants,
 12	  Tooltip
 13	} from '@patternfly/react-core';
 14	import { EllipsisVIcon } from '@patternfly/react-icons';
 15	import * as React from 'react';
 16	import { useTranslation } from 'react-i18next';
 17	import { exportToPng } from '../../../utils/export';
 18	import { useOutsideClickEvent } from '../../../utils/outside-hook';
 19	import { OverviewPanelId } from '../../../utils/overview-panels';
 20	import './panel-kebab.css';
 21	
 22	export type GraphOptipn = {
 23	  type: GraphType;
 24	  options?: GraphType[];
 25	};
 26	export type GraphType = 'donut' | 'bar' | 'line' | 'bar_line';
 27	
 28	export type PanelKebabOptions = {
 29	  showTop?: boolean;
 30	  showApp?: { text: string; value: boolean };
 31	  showAppDrop?: { text: string; value: boolean };
 32	  showOthers?: boolean;
 33	  showNoError?: boolean;
 34	  showInternal?: boolean;
 35	  showOutOfScope?: boolean;
 36	  showLast?: boolean;
 37	  graph?: GraphOptipn;
 38	};
 39	
 40	export interface PanelKebabProps {
 41	  id: OverviewPanelId;
 42	  options?: PanelKebabOptions;
 43	  setOptions?: (opts: PanelKebabOptions) => void;
 44	  isDark?: boolean;
 45	}
 46	
 47	export const PanelKebab: React.FC<PanelKebabProps> = ({ id, options, setOptions, isDark }) => {
 48	  const { t } = useTranslation('plugin__netobserv-plugin');
 49	  const ref = useOutsideClickEvent(() => setShowOptions(false));
 50	  const [showOptions, setShowOptions] = React.useState(false);
 51	
 52	  const setShowTop = React.useCallback(
 53	    (event: React.FormEvent<HTMLInputElement>, checked: boolean) => {
 54	      setOptions!({ ...options, showTop: checked });
 55	    },
 56	    [setOptions, options]
 57	  );
 58	
 59	  const setShowApp = React.useCallback(
 60	    (event: React.FormEvent<HTMLInputElement>, checked: boolean) => {
 61	      setOptions!({ ...options, showApp: { ...options!.showApp!, value: checked } });
 62	    },
 63	    [setOptions, options]
 64	  );
 65	
 66	  const setShowAppDrop = React.useCallback(
 67	    (event: React.FormEvent<HTMLInputElement>, checked: boolean) => {
 68	      setOptions!({ ...options, showAppDrop: { ...options!.showAppDrop!, value: checked } });
 69	    },
 70	    [setOptions, options]
 71	  );
 72	
 73	  const setShowOthers = React.useCallback(
 74	    (event: React.FormEvent<HTMLInputElement>, checked: boolean) => {
 75	      setOptions!({ ...options, showOthers: checked });
 76	    },
 77	    [setOptions, options]
 78	  );
 79	
 80	  const setShowNoError = React.useCallback(
 81	    (event: React.FormEvent<HTMLInputElement>, checked: boolean) => {
 82	      setOptions!({ ...options, showNoError: checked });
 83	    },
 84	    [setOptions, options]
 85	  );
 86	
 87	  const setShowInternal = React.useCallback(
 88	    (event: React.FormEvent<HTMLInputElement>, checked: boolean) => {
 89	      setOptions!({ ...options, showInternal: checked });
 90	    },
 91	    [setOptions, options]
 92	  );
 93	
 94	  const setShowOutOfScope = React.useCallback(
 95	    (event: React.FormEvent<HTMLInputElement>, checked: boolean) => {
 96	      setOptions!({ ...options, showOutOfScope: checked });
 97	    },
 98	    [setOptions, options]
 99	  );
100	
101	  const setShowLast = React.useCallback(
102	    (event: React.FormEvent<HTMLInputElement>, checked: boolean) => {
103	      setOptions!({ ...options, showLast: checked });
104	    },
105	    [setOptions, options]
106	  );
107	
108	  const setGraph = React.useCallback(
109	    (type: GraphType) => {
110	      setOptions!({ ...options, graph: { ...options!.graph!, type } });
111	    },
112	    [setOptions, options]
113	  );
114	
115	  const onOverviewExport = React.useCallback(() => {
116	    const overview_flex = document.getElementById(id)?.children[0] as HTMLElement | undefined;
117	    setShowOptions(false);
118	    setTimeout(() => {
119	      exportToPng('overview_panel', overview_flex as HTMLElement, isDark, id);
120	    }, 100);
121	  }, [id, isDark]);
122	
123	  const getGraphTypes = React.useCallback(() => {
124	    if (!options?.graph || !options.graph.options || !options?.graph?.options?.length) {
125	      return <></>;
126	    }
127	
128	    return (
129	      <div key={`${id}-graph-type`}>
130	        <DropdownGroup label={t('Graph type')}>
131	          {options!.graph!.options.includes('donut') && (
132	            <DropdownItem>
133	              {
134	                <Radio
135	                  isChecked={!options.graph || options.graph.type === 'donut'}
136	                  name="graph-donut"
137	                  onChange={() => setGraph('donut')}
138	                  label={t('Donut')}
139	                  id="graph-donut"
140	                />
141	              }
142	            </DropdownItem>
143	          )}
144	          {options!.graph!.options.includes('bar') && (
145	            <DropdownItem>
146	              <Radio
147	                isChecked={options.graph.type === 'bar'}
148	                name="graph-bar"
149	                onChange={() => setGraph('bar')}
150	                label={t('Bars')}
151	                id="graph-bar"
152	              />
153	            </DropdownItem>
154	          )}
155	          {options!.graph!.options.includes('line') && (
156	            <DropdownItem>
157	              <Radio
158	                isChecked={options.graph.type === 'line'}
159	                name="graph-line"
160	                onChange={() => setGraph('line')}
161	                label={t('Lines')}
162	                id="graph-line"
163	              />
164	            </DropdownItem>
165	          )}
166	          {options!.graph!.options.includes('bar_line') && (
167	            <DropdownItem>
168	              <Radio
169	                isChecked={options.graph.type === 'bar_line'}
170	                name="graph-bar-line"
171	                onChange={() => setGraph('bar_line')}
172	                label={t('Bars and lines')}
173	                id="graph-bar-line"
174	              />
175	            </DropdownItem>
176	          )}
177	        </DropdownGroup>
178	        <Divider key="first-divider" component="li" />
179	      </div>
180	    );
181	    // eslint-disable-next-line react-hooks/exhaustive-deps
182	  }, [id, options, setGraph]);
183	
184	  const items = [];
185	  if (options?.graph?.options?.length) {
186	    items.push(getGraphTypes());
187	  }
188	
189	  if (options?.showInternal !== undefined) {
190	    items.push(
191	      <DropdownItem key={`${id}-show-internal`}>
192	        <Tooltip
193	          content={
194	            <Text component={TextVariants.p}>
195	              {t(
196	                // eslint-disable-next-line max-len
197	                'Show scope-internal traffic, depending on the selected scope (e.g. node-internal traffic, namespace-internal traffic)'
198	              )}
199	            </Text>
200	          }
201	        >
202	          <Checkbox
203	            id={`${id}-show-internal`}
204	            isChecked={options.showInternal}
205	            onChange={setShowInternal}
206	            label={t('Show internal')}
207	            aria-label="Show internal"
208	          />
209	        </Tooltip>
210	      </DropdownItem>
211	    );
212	  }
213	
214	  if (options?.showOutOfScope !== undefined) {
215	    items.push(
216	      <DropdownItem key={`${id}-show-out-of-scope`}>
217	        <Tooltip
218	          content={
219	            <Text component={TextVariants.p}>
220	              {t('Show out of scope traffic (e.g. host-network traffic when scope is different from "Node")')}
221	            </Text>
222	          }
223	        >
224	          <Checkbox
225	            id={`${id}-show-out-of-scope`}
226	            isChecked={options.showOutOfScope}
227	            onChange={setShowOutOfScope}
228	            label={t('Show out of scope')}
229	            aria-label="Show out of scope"
230	          />
231	        </Tooltip>
232	      </DropdownItem>
233	    );
234	  }
235	
236	  // graph specific options
237	  switch (options?.graph?.type) {
