240	        items.push(
241	          <DropdownItem key={`${id}-show-others`}>
242	            <Tooltip
243	              content={<Text component={TextVariants.p}>{t('Show other traffic grouped in a separate series')}</Text>}
244	            >
245	              <Checkbox
246	                id={`${id}-show-others`}
247	                isChecked={options.showOthers}
248	                onChange={setShowOthers}
249	                label={t('Show others')}
250	                aria-label="Show others"
251	              />
252	            </Tooltip>
253	          </DropdownItem>
254	        );
255	      }
256	
257	      if (options?.showLast !== undefined) {
258	        items.push(
259	          <DropdownItem key={`${id}-last`}>
260	            <Tooltip
261	              content={<Text component={TextVariants.p}>{t('Show latest metrics of the selected timerange.')}</Text>}
262	            >
263	              <Checkbox
264	                id={`${id}-last`}
265	                isChecked={options.showLast}
266	                onChange={setShowLast}
267	                label={t('Show latest')}
268	                aria-label="Show latest"
269	              />
270	            </Tooltip>
271	          </DropdownItem>
272	        );
273	      }
274	      break;
275	    case 'bar':
276	    case 'line':
277	    case 'bar_line':
278	      if (options?.showTop !== undefined) {
279	        items.push(
280	          <DropdownItem key={`${id}-show-top`}>
281	            <Tooltip content={<Text component={TextVariants.p}>{t('Show top traffic for the selected filters')}</Text>}>
282	              <Checkbox
283	                id={`${id}-show-top`}
284	                isChecked={options.showTop}
285	                onChange={setShowTop}
286	                label={t('Show top')}
287	                aria-label="Show top"
288	              />
289	            </Tooltip>
290	          </DropdownItem>
291	        );
292	      }
293	
294	      if (options?.showApp !== undefined) {
295	        items.push(
296	          <DropdownItem key={`${id}-show-app`}>
297	            <Tooltip content={<Text component={TextVariants.p}>{t('Show overall for the selected filters')}</Text>}>
298	              <Checkbox
299	                id={`${id}-show-app`}
300	                isChecked={options.showApp.value}
301	                onChange={setShowApp}
302	                label={options.showApp.text}
303	                aria-label="Show overall"
304	              />
305	            </Tooltip>
306	          </DropdownItem>
307	        );
308	
309	        if (options?.showAppDrop !== undefined) {
310	          items.push(
311	            <DropdownItem key={`${id}-show-app-drop`}>
312	              <Tooltip
313	                content={<Text component={TextVariants.p}>{t('Show overall dropped for the selected filters')}</Text>}
314	              >
315	                <Checkbox
316	                  id={`${id}-show-app-drop`}
317	                  isChecked={options.showAppDrop!.value}
318	                  onChange={setShowAppDrop}
319	                  label={options.showAppDrop.text}
320	                  aria-label="Show overall dropped"
321	                />
322	              </Tooltip>
323	            </DropdownItem>
324	          );
325	        }
326	      }
327	      break;
328	  }
329	
330	  if (options?.showNoError !== undefined) {
331	    items.push(
332	      <DropdownItem key={`${id}-show-noerror`}>
333	        <Tooltip
334	          content={<Text component={TextVariants.p}>{t('Show NoError responses grouped in a separate series')}</Text>}
335	        >
336	          <Checkbox
337	            id={`${id}-show-noerror`}
338	            isChecked={options.showNoError}
339	            isDisabled={options.graph?.type !== 'donut' && options.showTop === false}
340	            onChange={setShowNoError}
341	            label={t('Show NoError')}
342	            aria-label="Show NoError"
343	          />
344	        </Tooltip>
345	      </DropdownItem>
346	    );
347	  }
348	
349	  if (items.length > 1) {
350	    items.push(<Divider key="last-divider" component="li" />);
351	  }
352	  items.push(
353	    <DropdownItem key={`${id}-export`} onClick={onOverviewExport}>
354	      {t('Export panel')}
355	    </DropdownItem>
356	  );
357	
358	  return (
359	    <div id={`panel-kebab-${id}-container`} ref={ref}>
360	      <Dropdown
361	        id={`panel-kebab-${id}`}
362	        className="panel-kebab"
363	        toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
364	          <MenuToggle
365	            ref={toggleRef}
366	            aria-label="kebab dropdown toggle"
367	            variant="plain"
368	            onClick={() => setShowOptions(!showOptions)}
369	            isExpanded={showOptions}
370	          >
371	            <EllipsisVIcon />
372	          </MenuToggle>
373	        )}
374	        isOpen={showOptions}
375	        popperProps={{
376	          position: 'right'
377	        }}
378	      >
379	        {items}
380	      </Dropdown>
381	    </div>
382	  );
383	};

